import { type AriaRole, type JSX, type ReactNode, type PropsWithChildren, ExoticComponent } from 'react';
import type { BehaviorTrackingProps } from '../../../../../core/types/behavior-tracking-props.js';
import type { DataTestId } from '../../../../../core/types/data-props.js';
import type { MaskingProps } from '../../../../../core/types/masking-props.js';
import type { Orientation } from '../../../../../core/types/orientation.js';
import type { StylingProps } from '../../../../../core/types/styling-props.js';
import type { AriaLabel } from '../../../types/aria-label.js';
import type { Dimensions } from '../../../types/dimensions.js';
import type { ChartLegendOrientation, LegendPosition, LegendRatio } from '../../../types/legend.js';
/**
 * @internal
 */
export interface ChartLayoutProps extends StylingProps, MaskingProps, DataTestId, AriaLabel, BehaviorTrackingProps {
    /**
     * Role of the chart container element.
     */
    role?: AriaRole;
    /**
     * Component identifier for behavioral tracking
     * @internal
     */
    'data-dt-component'?: string;
    /**
     * width of the chart
     */
    chartWidth?: string | number;
    /**
     * height of the chart
     */
    chartHeight?: string | number;
    /**
     * When true, indicates that the chart has the empty state enabled.
     */
    isEmpty?: boolean;
    /**
     * Template for the empty state.
     */
    emptyState?: ReactNode;
    /**
     * Template for the error state.
     */
    errorState?: ReactNode | ((message: string) => JSX.Element);
    /**
     * When true, shows a loading distractor.
     */
    showLoader?: boolean;
}
/**
 * @internal
 */
export interface LegendProps extends StylingProps, MaskingProps {
    /**
     * Legend position
     * @defaultValue auto
     */
    position?: LegendPosition;
    /**
     * Number included in the range [0,100] which indicates the percentage, relative
     * to the container size (width when the legend is on the right, height otherwise),
     * that the legend will use for determining the size for its initial rendering.
     * (e.g. container 1000px ratio 25% = the legend will set its width to 250px).
     * The option 'auto' enable the automatic initialization depending on the content.
     * of the legend (optimal display).
     * @defaultValue 'auto'
     * @deprecated use 'initialRatio' instead.
     */
    ratio?: LegendRatio;
    /**
     * Number included in the range [0,100] which indicates the percentage, relative
     * to the container size (width when the legend is on the right, height otherwise),
     * that the legend will use for determining the size for its initial rendering.
     * (e.g. container 1000px ratio 25% = the legend will set its width to 250px).
     * The option 'auto' enable the automatic initialization depending on the content.
     * of the legend (optimal display).
     * @defaultValue 'auto'
     */
    initialRatio?: LegendRatio;
    /**
     * Limits for the resize feature. It accepts values in the range [0,1].
     * (e.g. minWidth: 0.1 = the legend can't be resized with a value lower of the
     * 10% of the container width).
     * @defaultValue width [0.1,0.7], height [0.1,0.8]
     */
    ratioBoundaries?: ChartLayoutLegendSizes;
    /**
     * Callback used to override the ratio value on resize.
     */
    overrideRatio?: OverrideRatioFunction;
    /**
     * Handler called every time the consumer perform a resize event through the
     * resizer element.
     * @param ratio - current ratio value of the legend.
     */
    onResize?: (ratio: number) => void;
}
/**
 * @internal
 */
export type OverrideRatioFunction = (orientation: Orientation, width: number, height: number, ratio: LegendRatio, calculatedLegendDimensions: Dimensions) => Dimensions;
/**
 * Relative sizes for the legend in the range [0-1].
 * Example:
 * 0.2 represent the 20% of the whole container (plot + legend).
 * @internal
 */
export interface ChartLayoutLegendSizes {
    minWidth: number;
    minHeight: number;
    maxWidth: number;
    maxHeight: number;
}
/**
 * @internal
 */
export type ChartLayoutDimensions = Dimensions & {
    wrapperHeight: number;
    padding: {
        top: number;
        bottom: number;
        left: number;
        right: number;
    };
};
/**
 * @internal
 */
export type ProviderSlotProp = (props: PropsWithChildren) => JSX.Element;
/**
 * @internal
 */
export interface ChartLayoutSettings {
    provider: ExoticComponent<PropsWithChildren> | ProviderSlotProp;
    legendSettings: ChartLayoutLegendSettings;
    graphArea: ReactNode;
    legendArea?: ReactNode;
    containerAvailableArea: Dimensions;
}
/**
 * @internal
 */
export interface ChartLayoutLegendSettings {
    orientation: ChartLegendOrientation;
    hidden: boolean;
    showResizer: boolean;
    ratioBoundaries: ChartLayoutLegendSizes;
    ratio: LegendRatio;
    initialRatio?: LegendRatio;
    onResize?: (ratio: number) => void;
    overrideRatio?: OverrideRatioFunction;
}
/**
 * @internal
 */
export interface ChartLayoutGridSettings {
    layoutWidth: string;
    layoutHeight: string;
    templateAreas: string;
    gridTemplate: string;
}
/**
 * @internal
 */
export interface ChartLayoutRatioContextProps {
    ratio: LegendRatio;
    ratioBoundaries: ChartLayoutLegendSizes;
    overrideRatio?: OverrideRatioFunction;
    legendRef: (node: HTMLDivElement) => void;
    readyForAutoRatio: boolean;
    legendCandidateSize?: number;
}
/**
 * @internal
 */
export interface ChartLayoutRef {
    element: HTMLDivElement | null;
    refreshLegendSize: () => void;
}
